collect($locales)->map(function (string $localeLabel, string $locale) use ($field, $label, $textarea) {
            $component = $textarea
                ? Textarea::make("{$field}.{$locale}")
                : TextInput::make("{$field}.{$locale}");

            return $component
                ->label("{$label} ({$localeLabel})")
                ->required($locale === 'en')
                ->maxLength($textarea ? null : 255);
        })->all
